package com.interview.incidentrca.controller;
import com.interview.incidentrca.dto.*;import com.interview.incidentrca.enums.*;import com.interview.incidentrca.service.IncidentService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.http.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.time.Instant;import java.util.*;
@RestController @RequestMapping("/api/incidents") @RequiredArgsConstructor public class IncidentController{private final IncidentService service;
 @PostMapping @PreAuthorize("hasAnyRole('ADMIN','ENGINEER')") ResponseEntity<IncidentResponse> create(@Valid @RequestBody IncidentCreateRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));}
 @GetMapping Page<IncidentResponse> all(@RequestParam(required=false) IncidentStatus status,@RequestParam(required=false) Severity severity,@RequestParam(required=false) String serviceName,@RequestParam(required=false) Long assignedEngineerId,@RequestParam(required=false) @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) Instant from,@RequestParam(required=false) @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) Instant to,Pageable pageable){return service.search(status,severity,serviceName,assignedEngineerId,from,to,pageable);} 
 @GetMapping("/{id}") IncidentResponse get(@PathVariable Long id){return service.get(id);} @PutMapping("/{id}") @PreAuthorize("hasAnyRole('ADMIN','ENGINEER')") IncidentResponse update(@PathVariable Long id,@Valid @RequestBody IncidentUpdateRequest r){return service.update(id,r);} @DeleteMapping("/{id}") @PreAuthorize("hasRole('ADMIN')") ResponseEntity<Void> delete(@PathVariable Long id){service.delete(id);return ResponseEntity.noContent().build();}
 @PatchMapping("/{id}/status") @PreAuthorize("hasAnyRole('ADMIN','ENGINEER')") IncidentResponse status(@PathVariable Long id,@Valid @RequestBody StatusUpdateRequest r){return service.changeStatus(id,r);} @PatchMapping("/{id}/assign") @PreAuthorize("hasAnyRole('ADMIN','ENGINEER')") IncidentResponse assign(@PathVariable Long id,@Valid @RequestBody AssignRequest r){return service.assign(id,r);} @PostMapping("/{id}/comments") @PreAuthorize("hasAnyRole('ADMIN','ENGINEER')") ResponseEntity<TimelineEventResponse> comment(@PathVariable Long id,@Valid @RequestBody CommentRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.comment(id,r));}
 @GetMapping("/{id}/timeline") List<TimelineEventResponse> timeline(@PathVariable Long id){return service.timeline(id);} @GetMapping("/{id}/root-cause-suggestions") List<RootCauseSuggestionResponse> rca(@PathVariable Long id){return service.suggestions(id);} @GetMapping("/{id}/duplicates") List<DuplicateIncidentResponse> duplicates(@PathVariable Long id){return service.duplicates(id);} }
